describe("MHPCO Claim Office тАФ CLI", () => {
  it("CLI reads a JSON scenario from stdin and writes a JSON results object to stdout (schema example 2: customer 5 yr, amulet quote then 200 fire claim тЖТ {results: [{premium: 58}, {payout: 0}]})", () => {
    const scenario = {
      customer: { yearsWithMHPCO: 5 },
      steps: [
        {
          op: "quote",
          items: [{ type: "amulet", enchantment: 2 }],
        },
        {
          op: "claim",
          policy: 0,
          incident: {
            cause: "fire",
            damages: [{ itemType: "amulet", amount: 200 }],
          },
        },
      ],
    };
    const proc = spawnSync("npx", ["tsx", "src/cli.ts"], {
      input: JSON.stringify(scenario),
      encoding: "utf-8",
    });
    expect(proc.status).toBe(0);
    expect(JSON.parse(proc.stdout)).toEqual({
      results: [{ premium: 58 }, { payout: 0 }],
    });
  });
});
